









import { Component, Vue, Prop } from 'vue-property-decorator';

export enum SlideDirection {
    Up    = 'up',
    Down  = 'down',
    Right = 'right',
    Left  = 'left',
}

@Component
export default class SlideFadeTransition extends Vue {
    @Prop({ default : SlideDirection.Down })
    direction: SlideDirection;
}
